const fs = require('fs');
const path = require('path');

const vaultPath = $('Set Vault Path').item.json.vaultPath;
const lookbackDays = $('Set Vault Path').item.json.lookbackDays;
const now = new Date();
const today = now.toISOString().slice(0,10);

const health = $('Hit Health').item?.json || { ok: false };
const status = $('Hit Status').item?.json || { ok: false };
const waitlist = $('Hit Waitlist Count').item?.json || {};

const runsRoot = path.join(vaultPath, 'JobFilter', 'Agent Runs');
const recentRuns = [];
let daysScanned = 0;
for (let d = 0; d < lookbackDays; d++) {
  const dt = new Date(now.getTime() - d * 86400000);
  const folder = path.join(runsRoot, dt.toISOString().slice(0,10));
  if (!fs.existsSync(folder)) continue;
  daysScanned++;
  const files = fs.readdirSync(folder).filter(f => f.endsWith('.md'));
  for (const f of files) {
    const stat = fs.statSync(path.join(folder, f));
    recentRuns.push({ date: dt.toISOString().slice(0,10), file: f, size: stat.size });
  }
}

const jobFolder = path.join(vaultPath, 'JobFilter');
const changelogs = fs.existsSync(jobFolder)
  ? fs.readdirSync(jobFolder).filter(f => f.startsWith('Changelog ') && f.endsWith('.md')).sort().reverse().slice(0, 3)
  : [];

const md = `---\ntype: daily-brief\nproject: JobFilter\nrun_at: ${now.toISOString()}\nfor_date: ${today}\nstatus: ${health.ok ? 'healthy' : 'degraded'}\ntags: [jobfilter, daily-brief, llm-context]\n---\n\n# JobFilter Daily Brief — ${today}\n\n> **LLM agents**: canonical morning context. Read first. Then \`AGENTS.md\` for vault rules. Then \`n8n Agent Roster.md\` for automation surface.\n\n## North star\n- Lead quality > volume\n- One paid-tier-worthy lead per week\n- Free tier useful, real value behind subscription\n\n## System health (just polled)\n- API health: \`${JSON.stringify(health)}\`\n- Source status: \`${JSON.stringify(status).slice(0, 400)}\`\n- Waitlist: \`${JSON.stringify(waitlist)}\`\n\n## Last ${daysScanned} days of agent activity\n${recentRuns.length === 0 ? '_No agent runs yet — automation queue still building._' : ''}\n${recentRuns.slice(0, 30).map(r => '- ' + r.date + ' · ' + r.file + ' (' + r.size + 'b)').join('\n')}\n${recentRuns.length > 30 ? '\n_+' + (recentRuns.length - 30) + ' more runs not listed_' : ''}\n\n## Recent changelogs\n${changelogs.map(c => '- [[' + c.replace('.md','') + ']]').join('\n') || '_none_'}\n\n## What an LLM should do next\n1. Read \`JobFilter/RALPH_PLAN.md\` — find top unchecked item\n2. Execute it\n3. Commit + push\n4. Update RALPH_PLAN check + done log\n\n## Related\n- [[AGENTS]]\n- [[n8n Agent Roster]]\n- [[RALPH_PLAN]]\n- [[Vault Map]]\n`;

const briefPath = path.join(vaultPath, 'JobFilter', 'Daily Brief.md');
return [{
  json: { briefPath, today, runCount: recentRuns.length, daysScanned, content: md },
  binary: {
    data: {
      data: Buffer.from(md, 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'Daily Brief.md',
      fileExtension: 'md'
    }
  }
}];
